import React, { useState, useEffect } from 'react';
import api from './api';
import BudgetForm from './components/BudgetForm';
import InvestmentForm from './components/InvestmentForm';
import AnalyticsDashboard from './components/AnalyticsDashboard';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('dashboard');
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState([]);
  const [investments, setInvestments] = useState([]);

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/register', { 
        name: e.target.name.value, 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      alert('Registered! Please login.');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const logout = () => {
    setToken(null);
    localStorage.removeItem('token');
  };

  const loadTransactions = async () => {
    try {
      const res = await api.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadBudgets = async () => {
    try {
      const res = await api.get('/budgets');
      setBudgets(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadInvestments = async () => {
    try {
      const res = await api.get('/investments');
      setInvestments(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (token) {
      loadTransactions();
      loadBudgets();
      loadInvestments();
    }
  }, [token]);

  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full">
          <h1 className="text-3xl font-bold text-center text-gray-800 mb-8">FinTrack</h1>
          <form onSubmit={login} className="space-y-4 mb-6">
            <input name="email" type="email" placeholder="Email" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <input name="password" type="password" placeholder="Password" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <button type="submit" className="w-full bg-blue-500 text-white p-3 rounded-lg font-semibold hover:bg-blue-600 transition">Login</button>
          </form>
          <div className="text-center py-4 border-t">
            <p className="text-sm text-gray-600 mb-2">New user?</p>
            <form onSubmit={register} className="space-y-2">
              <input name="name" type="text" placeholder="Full Name" className="w-full p-3 border border-gray-300 rounded-lg text-sm" required />
              <input name="email" type="email" placeholder="Email" className="w-full p-3 border border-gray-300 rounded-lg text-sm" required />
              <input name="password" type="password" placeholder="Password (6+ chars)" className="w-full p-3 border border-gray-300 rounded-lg text-sm" required />
              <button type="submit" className="w-full bg-green-500 text-white p-3 rounded-lg font-semibold hover:bg-green-600 transition text-sm">Register</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  const refreshAll = () => {
    loadTransactions();
    loadBudgets();
    loadInvestments();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50">
      <nav className="bg-white/80 backdrop-blur-md shadow-lg border-b">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-4">
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              FinTrack
            </h1>
            <span className="text-sm text-gray-500">Welcome, {user?.name}</span>
          </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-full font-medium transition ${view === 'dashboard' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:text-blue-600'}`}>Dashboard</button>
            <button onClick={() => setView('transactions')} className={`px-4 py-2 rounded-full font-medium transition ${view === 'transactions' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:text-blue-600'}`}>Transactions</button>
            <button onClick={() => setView('budgets')} className={`px-4 py-2 rounded-full font-medium transition ${view === 'budgets' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:text-blue-600'}`}>Budgets</button>
            <button onClick={() => setView('investments')} className={`px-4 py-2 rounded-full font-medium transition ${view === 'investments' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:text-blue-600'}`}>Investments</button>
            <button onClick={() => setView('analytics')} className={`px-4 py-2 rounded-full font-medium transition ${view === 'analytics' ? 'bg-blue-100 text-blue-700' : 'text-gray-600 hover:text-blue-600'}`}>Analytics</button>
            <button onClick={logout} className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-full font-semibold transition ml-2">Logout</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-8">
        <div className="mb-8 flex justify-between items-center">
          <h2 className="text-3xl font-bold text-gray-800 capitalize">{view}</h2>
          <button onClick={refreshAll} className="bg-blue-500 hover:bg-blue-600 text-white px-6 py-2 rounded-full font-medium transition">
            Refresh
          </button>
        </div>

        {view === 'dashboard' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-white rounded-2xl shadow-xl p-8">
              <h3 className="text-xl font-bold mb-6 text-gray-800">Quick Stats</h3>
              <div className="space-y-4">
                <div className="flex justify-between">
                  <span>Total Income (This Month)</span>
                  <span className="font-bold text-green-600">${transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + parseFloat(t.amount), 0).toFixed(2)}</span>
                </div>
                <div className="flex justify-between">
                  <span>Total Expenses (This Month)</span>
                  <span className="font-bold text-red-600">${transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + parseFloat(t.amount), 0).toFixed(2)}</span>
                </div>
                <div className="flex justify-between pt-4 border-t">
                  <span>Recent Transactions</span>
                  <span className="text-sm text-gray-500">{transactions.length}</span>
                </div>
              </div>
            </div>
            <AnalyticsDashboard />
          </div>
        )}

        {view === 'transactions' && (
          <div>
            <BudgetForm onAdd={refreshAll} />
            <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
              <div className="p-6 border-b bg-gray-50">
                <h3 className="text-xl font-bold text-gray-800 mb-2">Transactions ({transactions.length})</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Date</th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Type</th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Category</th>
                      <th className="px-6 py-4 text-right text-sm font-semibold text-gray-700">Amount</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {transactions.slice().reverse().map((t) => (
                      <tr key={t.id}>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{t.date}</td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${t.type === 'income' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                            {t.type.toUpperCase()}
                          </span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 capitalize">{t.category}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-right">
                          <span className={t.type === 'income' ? 'text-green-600' : 'text-red-600'}>
                            ${parseFloat(t.amount).toFixed(2)}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {view === 'budgets' && (
          <div>
            <BudgetForm onAdd={refreshAll} />
            <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="px-6 py-4 text-left">Month</th>
                    <th className="px-6 py-4 text-right">Limit</th>
                    <th className="px-6 py-4 text-right">Usage</th>
                  </tr>
                </thead>
                <tbody>
                  {budgets.map(b => (
                    <tr key={b.id}>
                      <td className="px-6 py-4">{new Date(b.month).toLocaleDateString('en-US', { year: 'numeric', month: 'long' })}</td>
                      <td className="px-6 py-4 font-semibold">${b.limit}</td>
                      <td className="px-6 py-4">
                        <div className="w-full bg-gray-200 rounded-full h-2">
                          <div className="bg-blue-600 h-2 rounded-full" style={{width: b.usage || '0%'}}></div>
                        </div>
                        <span className="ml-2">{b.usage || '0%'}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {view === 'investments' && (
          <div>
            <InvestmentForm onAdd={refreshAll} />
            <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="px-6 py-4 text-left">Principal</th>
                    <th className="px-6 py-4 text-left">Rate</th>
                    <th className="px-6 py-4 text-left">Duration</th>
                    <th className="px-6 py-4 text-right">ROI</th>
                    <th className="px-6 py-4 text-right">CAGR</th>
                  </tr>
                </thead>
                <tbody>
                  {investments.map(i => (
                    <tr key={i.id}>
                      <td className="px-6 py-4">${i.principal}</td>
                      <td className="px-6 py-4">{i.rate}%</td>
                      <td className="px-6 py-4">{i.duration}y</td>
                      <td className="px-6 py-4 text-green-600 font-bold">{i.roi}%</td>
                      <td className="px-6 py-4 text-blue-600 font-bold">{i.cagr}%</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {view === 'analytics' && (
          <AnalyticsDashboard />
        )}
      </main>
    </div>
  );
}

export default App;
